import "./css/Formations.css"
import { useState } from "react"
import { ChevronDown, X } from "@boxicons/react"

const formationsData = [
    {
        title: "EPITA",
        text: "Engineering school specialised in computer science."
    },
    {
        title: "ISG",
        text: "Business school focused on management and entrepreneurship."
    },
    {
        title: "Griffith College Dublin",
        text: "International semester studying computing."
    }
]

const Formations = () => {

    const [activeIndex, setActiveIndex] = useState(null)

    const toggleFormation = (index) => {
        setActiveIndex(activeIndex === index ? null : index)
    }

    return (
        <div className="formations">

            <h1 className="formations-title">Formations</h1>

            {formationsData.map((formation, index) => (

                <div 
                    key={index}
                    className={`formation ${activeIndex === index ? "active" : ""}`}
                >

                    <h3 className="formation-title">
                        {formation.title}
                    </h3>

                    {activeIndex === index && (
                        <p className="formation-text">
                            {formation.text}
                        </p>
                    )}

                    <button
                        className="toggle"
                        onClick={() => toggleFormation(index)}
                    >
                        {activeIndex === index ? <X /> : <ChevronDown />}
                    </button>

                </div>

            ))}

        </div>
    )
}

export default Formations
